extern "C" {
#endif

/* Minimal opcode constants used by the prototype materializer. */
enum {
  SPON_OP_MOVE = 0,
  SPON_OP_LOADI = 1,
  SPON_OP_LOADK = 3,
  SPON_OP_LOADKX = 4,
  SPON_OP_LOADFALSE = 5,
  SPON_OP_LFALSESKIP = 6,
  SPON_OP_LOADTRUE = 7,
  SPON_OP_LOADNIL = 8,
  SPON_OP_ADDI = 21,
  SPON_OP_SHLI = 32,
  SPON_OP_SHRI = 33
};

enum {
  SPON_LUA_VNIL = 0,
  SPON_LUA_VFALSE = 1,
  SPON_LUA_VNUMINT = 3,
  SPON_LUA_VTRUE = 17
};

#define SPON_FACT_I64_SLOT(slot_) (((SponFactSig)1) << (slot_))

typedef struct SponL1Op {
  uint32_t opcode;
  int32_t a;
  int32_t b;
  int32_t c;
  int32_t bx;
  int32_t ax;
  int32_t sbx;
  int32_t sj;
} SponL1Op;

typedef struct SponL1Image {
  uint8_t *code;
  size_t code_size;
  uint32_t n_choices;
  SponSelectStats select_stats;
} SponL1Image;

void spon_l1_image_init(SponL1Image *img);
void spon_l1_image_free(SponL1Image *img);

/*
 * Select L1 native stencils from the generated bank and copy/link/patch them
 * into one executable image. This is a prototype projection interpreter step:
 * bytecode+facts -> bank choices -> native image. It does not run SSA.
 */
int spon_l1_project(const SponL1Op *ops, uint32_t start, uint32_t end,
                    SponFactSig entry_sig, SponFactSig observed_sig,
                    SponL1Image *out_img);

/* Execute a previously projected image. Returns ctx->exit_kind. */
uint32_t spon_l1_run(const SponL1Image *img, SponExecCtx *ctx);

/* Convenience helper: project, run once, then free the image. */
uint32_t spon_l1_interpret_once(const SponL1Op *ops, uint32_t start, uint32_t end,
                                SponFactSig entry_sig, SponFactSig observed_sig,
                                SponExecCtx *ctx);

