#!/usr/bin/env luajit

package.path = "./?.lua;./?/init.lua;./experiments/lua_interpreter_vm/spongejit/?.lua;" .. package.path

local ffi = require("ffi")
local bit = require("bit")
local Constants = require("experiments.lua_interpreter_vm.src.constants")

ffi.cdef[[
typedef unsigned int uint32_t;
typedef unsigned short uint16_t;
typedef unsigned long long uint64_t;
typedef uint64_t SponFactSig;
typedef uint32_t SponStencilId;

typedef struct {
  uint32_t code_offset;
  uint16_t reloc_kind;
  uint16_t edge_kind;
  uint16_t endpoint_index;
  int32_t target_delta;
} SponControlReloc;

typedef struct {
  SponStencilId stencil_id;
  uint32_t offset;
  uint32_t size;
  uint32_t endpoint_start;
  uint32_t data_reloc_start;
  uint32_t control_reloc_start;
  uint32_t slotmap_start;
  uint32_t projection_start;
  uint32_t dependency_start;
  uint16_t len;
  uint16_t n_endpoints;
  uint16_t n_data_relocs;
  uint16_t n_control_relocs;
  uint16_t n_slotmaps;
  uint16_t n_projections;
  uint16_t n_dependencies;
  uint16_t flags;
  uint16_t physical_abi;
  uint16_t reserved;
  uint64_t pattern_key;
  SponFactSig selector_sig;
  SponFactSig required_sig;
  SponFactSig checked_sig;
  SponFactSig produced_sig;
  SponFactSig killed_sig;
} SponStencilDesc;

uint32_t spon_bank_stencil_count(void);
const SponStencilDesc *spon_get_stencil(SponStencilId id);
const unsigned char *spon_stencil_data(SponStencilId id);
const SponControlReloc *spon_stencil_control_relocs(SponStencilId id, uint32_t *out_n);
SponStencilId spon_l0_stencil_for_opcode(uint32_t opcode);
]]

local bank_path = "experiments/lua_interpreter_vm/spongejit/build/sponbank/libsponbank.so"
local f = io.open(bank_path, "rb")
assert(f, "missing generated L1 bank: " .. bank_path)
f:close()

local bank = ffi.load(bank_path)
assert(bank.spon_bank_stencil_count() > 0, "empty generated bank")

local op_name = {}
for name, opcode in pairs(Constants.Op) do
  if type(opcode) == "number" and not op_name[opcode] then op_name[opcode] = name end
end

local strict = os.getenv("SPON_STRICT_SEMANTIC_L0") == "1"
local missing, bad = {}, {}
for opcode = 0, 84 do
  local id = tonumber(bank.spon_l0_stencil_for_opcode(opcode))
  local name = op_name[opcode] or ("OP_" .. tostring(opcode))
  if id == 0 then
    missing[#missing + 1] = string.format("%d:%s", opcode, name)
  else
    local d = bank.spon_get_stencil(id)
    local data = bank.spon_stencil_data(id)
    if d == nil then
      bad[#bad + 1] = string.format("%d:%s id=%d missing descriptor", opcode, name, id)
    elseif bit.band(tonumber(d.flags), 10) ~= 10 then
      bad[#bad + 1] = string.format("%d:%s id=%d not exact native flags=%d", opcode, name, id, tonumber(d.flags))
    elseif tonumber(d.size) <= 0 or data == nil then
      bad[#bad + 1] = string.format("%d:%s id=%d no native bytes", opcode, name, id)
    else
      local nrel = ffi.new("uint32_t[1]")
      local rels = bank.spon_stencil_control_relocs(id, nrel)
      for i = 0, tonumber(nrel[0]) - 1 do
        local edge = tonumber(rels[i].edge_kind)
        if edge < 1 or edge > 4 then
          bad[#bad + 1] = string.format("%d:%s id=%d unknown control edge=%d", opcode, name, id, edge)
        end
      end
    end
  end
end

assert(#bad == 0, "bad semantic L0 bank entries: " .. table.concat(bad, "; "))
if strict then
  assert(#missing == 0, "strict semantic L0 coverage missing opcodes: " .. table.concat(missing, ", "))
else
  io.stderr:write(string.format("[semantic-l0] exact native L0 entries=%d missing=%d\n", 85 - #missing, #missing))
end

print("ok - SpongeJIT generated bank reports truthful semantic L0 coverage")

#!/usr/bin/env luajit
-- Backward-compatible wrapper for the truthful semantic L0 audit.

dofile("experiments/lua_interpreter_vm/tests/test_spongejit_semantic_l0_coverage.lua")

#!/usr/bin/env luajit

package.path = "./?.lua;./?/init.lua;./experiments/lua_interpreter_vm/spongejit/?.lua;" .. package.path

local ffi = require("ffi")
local Constants = require("experiments.lua_interpreter_vm.src.constants")

ffi.cdef[[
typedef unsigned int uint32_t;
typedef unsigned short uint16_t;
typedef unsigned long long uint64_t;
typedef uint64_t SponFactSig;
typedef uint32_t SponStencilId;

typedef struct {
  SponStencilId stencil_id;
  uint32_t pc_start;
  uint32_t pc_end;
} SponStencilChoice;

typedef struct {
  uint64_t pattern_probes;
  uint64_t candidate_checks;
  uint32_t choices;
  uint32_t status;
  uint32_t covered_end;
  uint32_t first_uncovered_pc;
  uint32_t no_candidate_opcode;
} SponSelectStats;

typedef struct {
  uint16_t op_idx;
  uint8_t logical_slot;
  uint8_t field_kind;
} SponSlotMapEntry;

const SponStencilChoice *spon_select_flow_flags_slots_stats(const uint32_t *bc, uint32_t start, uint32_t end,
                                                           SponFactSig entry_sig, SponFactSig observed_sig,
                                                           uint16_t required_stencil_flags,
                                                           const SponSlotMapEntry *actual_slots,
                                                           uint32_t n_actual_slots,
                                                           uint32_t *out_n,
                                                           SponSelectStats *stats);
]]

local function assert_eq(a, b, msg) if a ~= b then error((msg or "assert_eq failed") .. ": " .. tostring(a) .. " ~= " .. tostring(b), 2) end end

local bank_path = "experiments/lua_interpreter_vm/spongejit/build/sponbank/libsponbank.so"
local f = io.open(bank_path, "rb")
assert(f, "missing generated L1 bank: run cd experiments/lua_interpreter_vm/spongejit && make stencils && make bank")
f:close()

local bank = ffi.load(bank_path)
local bc = ffi.new("uint32_t[1]")
bc[0] = Constants.Op.LOADF
local slots = ffi.new("SponSlotMapEntry[1]")
slots[0].op_idx = 0
slots[0].logical_slot = 0
slots[0].field_kind = 1
local out_n = ffi.new("uint32_t[1]")
local stats = ffi.new("SponSelectStats")
bank.spon_select_flow_flags_slots_stats(bc, 0, 1, 0, 0, 10, slots, 1, out_n, stats)
assert_eq(tonumber(out_n[0]), 0, "unsupported opcode must not produce a hidden fallback choice")
assert_eq(tonumber(stats.status), 1, "selector status")
assert_eq(tonumber(stats.covered_end), 0, "covered_end")
assert_eq(tonumber(stats.first_uncovered_pc), 0, "first_uncovered_pc")
assert_eq(tonumber(stats.no_candidate_opcode), Constants.Op.LOADF, "no_candidate_opcode")

print("ok - SpongeJIT selector reports missing coverage without fallback")

